class Solution {
    private static final int MOD = 1000000007;
    private static final int MAXN = 500;

    private long[] fact = new long[MAXN + 1];
    private long[] invFact = new long[MAXN + 1];

    public Solution() {
        precompute();
    }

    // Fast exponentiation: a^b % MOD
    private long modPow(long a, long b) {
        long result = 1;
        while (b > 0) {
            if ((b & 1) == 1)
                result = (result * a) % MOD;
            a = (a * a) % MOD;
            b >>= 1;
        }
        return result;
    }

    // Precompute factorials and inverse factorials
    private void precompute() {
        fact[0] = 1;
        for (int i = 1; i <= MAXN; i++) {
            fact[i] = (fact[i - 1] * i) % MOD;
        }

        invFact[MAXN] = modPow(fact[MAXN], MOD - 2);
        for (int i = MAXN - 1; i >= 0; i--) {
            invFact[i] = (invFact[i + 1] * (i + 1)) % MOD;
        }
    }

    public long countSmeagoleseAnagrams(String S) {
        long result = fact[S.length()];

        Map<Character, Integer> freq = new HashMap<>();
        for (char c : S.toCharArray()) {
            freq.put(c, freq.getOrDefault(c, 0) + 1);
        }

        for (int count : freq.values()) {
            result = (result * invFact[count]) % MOD;
        }

        return result;
    }
}

