class Solution {
    constructor() {
        this.MOD = 1000000007n;
        this.MAXN = 500;

        this.fact = Array(this.MAXN + 1).fill(0n);
        this.invFact = Array(this.MAXN + 1).fill(0n);

        this.precompute();
    }

    // Fast power: a^b % MOD (BigInt)
    modPow(a, b) {
        let result = 1n;
        while (b > 0n) {
            if (b & 1n) result = (result * a) % this.MOD;
            a = (a * a) % this.MOD;
            b >>= 1n;
        }
        return result;
    }

    // Precompute factorials and inverse factorials
    precompute() {
        this.fact[0] = 1n;
        for (let i = 1; i <= this.MAXN; i++) {
            this.fact[i] = (this.fact[i - 1] * BigInt(i)) % this.MOD;
        }

        // Fermat's Little Theorem for inverse factorial
        this.invFact[this.MAXN] = this.modPow(
            this.fact[this.MAXN],
            this.MOD - 2n
        );

        for (let i = this.MAXN - 1; i >= 0; i--) {
            this.invFact[i] =
                (this.invFact[i + 1] * BigInt(i + 1)) % this.MOD;
        }
    }

    countSmeagoleseAnagrams(S) {
        const freq = new Map();
        for (const ch of S) {
            freq.set(ch, (freq.get(ch) || 0) + 1);
        }

        let result = this.fact[S.length];
        for (const count of freq.values()) {
            result = (result * this.invFact[count]) % this.MOD;
        }

        return result.toString();
    }
}
